import React, { useEffect, useState } from "react";
import { ComposableMap, Geographies, Geography } from "react-simple-maps";
import { fetchCountries } from "./firebaseData";

const geoUrl = "https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json";

function MapChart() {
  const [countries, setCountries] = useState([]);
  const [popup, setPopup] = useState(null);
  const [showInstructions, setShowInstructions] = useState(true);

  useEffect(() => {
    fetchCountries().then(setCountries);
  }, []);

  const displayCountries = countries.sort((a, b) => a.rank - b.rank);

  const getColor = (countryName) => {
    const found = displayCountries.find(
      (c) => c.name.toLowerCase() === countryName.toLowerCase()
    );
    if (!found) return "#90CAF9";
    if (found.rank <= 10) return "red";
    if (found.rank <= 20) return "orange";
    if (found.rank <= 25) return "yellow";
    return "#1e88e5";
  };

  const handleCountryClick = (event, countryName) => {
    const found = displayCountries.find(
      (c) => c.name.toLowerCase() === countryName.toLowerCase()
    );

    setPopup({
      name: countryName,
      rate: found?.rate ?? null,
      type: found?.type ?? "Largely Safe",
      rank: found?.rank ?? null,
      x: event.pageX,
      y: event.pageY,
    });
  };

  return (
    <div style={{ height: "100vh", position: "relative" }}>

      {/* Link Section */}
      <div
        style={{
          position: "absolute",
          bottom: "10px",
          left: "50%",
          transform: "translateX(-50%)",
          fontSize: "20px",
          background: "white",
          padding: "6px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.15)",
          zIndex: 2000,
        }}
      >
        <a
          href="https://compudonjunior.in"
          target="_blank"
          rel="noopener noreferrer"
          style={{ color: "#1e88e5", textDecoration: "none", fontWeight: 600 }}
        >
          Visit Our Website
        </a>
      </div>

      {/* Instructions Section */}
      {showInstructions && (
  <div
    style={{
      position: "absolute",
      top: "70px",
      left: "50%",
      transform: "translateX(-50%)",
      width: "min(90vw, 450px)", // ⬅ Bigger width
      backgroundColor: "white",
      borderRadius: "18px",       // ⬅ Softer corners
      padding: "24px",            // ⬅ More padding
      boxShadow: "0 8px 30px rgba(0,0,0,0.25)",
      zIndex: 1500,
    }}
  >
    {/* BIG CLEAR X BUTTON */}
    <div
      style={{
        position: "absolute",
        top: "10px",
        right: "12px",
        cursor: "pointer",
        fontSize: "26px",         // ⬅ Larger
        fontWeight: 700,          // ⬅ Thicker
        width: "32px",
        height: "32px",           // ⬅ Clickable area
        borderRadius: "50%",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        backgroundColor: "#f0f0f0",
        boxShadow: "0 2px 6px rgba(0,0,0,0.15)",
        transition: "0.2s",
      }}
      onClick={() => setShowInstructions(false)}
      onMouseEnter={(e) => (e.target.style.backgroundColor = "#e0e0e0")}
      onMouseLeave={(e) => (e.target.style.backgroundColor = "#f0f0f0")}
    >
      ×
    </div>

    <h3 style={{ marginTop: "10px", marginBottom: "16px", fontSize: "22px" }}>
      How to Use This Map
    </h3>

    <p style={{ margin: "8px 0", fontSize: "17px", lineHeight: 1.6 }}>
      • Click on any country to view cyberbullying data.
    </p>
    <p style={{ margin: "8px 0", fontSize: "17px", lineHeight: 1.6 }}>
      • Click outside a country-specific popup to close it.
    </p>
    <p style={{ margin: "8px 0", fontSize: "17px", lineHeight: 1.6 }}>
      • Higher ranking means higher cyberbullying prevalence.
    </p>
  </div>
)}


      {/* Map Section */}
      <div
        style={{
          width: "100%",
          height: "100%",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
        }}
      >
        <ComposableMap
          projection="geoEqualEarth"
          projectionConfig={{ scale: 140, center: [0, 10] }}
          style={{ width: "100%", height: "auto" }}
        >
          <Geographies geography={geoUrl}>
            {({ geographies }) =>
              geographies.map((geo) => {
                const countryName = geo.properties.name;
                const fillColor = getColor(countryName);

                return (
                  <Geography
                    key={geo.rsmKey}
                    geography={geo}
                    onClick={(e) => handleCountryClick(e, countryName)}
                    style={{
                      default: {
                        fill: fillColor,
                        outline: "none",
                        cursor: "pointer",
                      },
                      hover: { fill: "#90A4AE", outline: "none" },
                      pressed: { fill: "#FF7043", outline: "none" },
                    }}
                  />
                );
              })
            }
          </Geographies>
        </ComposableMap>
      </div>

      {/* Popup for Countries Section */}
{/* Popup for Countries Section */}
{popup && (
  <div
    onClick={(e) => e.stopPropagation()}
    style={{
      position: "absolute",
      left: popup.x,
      top: popup.y,
      transform: "translate(-50%, -100%)",
      backgroundColor: "rgba(255, 255, 255, 0.95)",
      border: "1px solid #ddd",
      borderRadius: "16px",
      padding: "16px 20px",
      boxShadow: "0 6px 15px rgba(0,0,0,0.25)",
      animation: "fadeOut 3s forwards",
      width: "min(80vw, 320px)",
      fontSize: "15px",
      textAlign: "center",
      zIndex: 1000,
    }}
  >
    {/* X Close Button */}
    <button
      onClick={() => setPopup(null)}
      style={{
        position: "absolute",
        top: "8px",
        right: "10px",
        background: "transparent",
        border: "none",
        fontSize: "24px",
        cursor: "pointer",
        color: "#666",
        lineHeight: 1,
      }}
      aria-label="Close popup"
    >
      X
    </button>

    <div style={{ fontWeight: 600, marginBottom: "6px", fontSize: "18px" }}>
      {popup.name}
    </div>

    {popup.rate ? (
      <>
        <div><strong>Rank:</strong> {popup.rank}</div>
        <div><strong>Bullied:</strong> {popup.rate}%</div>
        <div><strong>Cause/Trend:</strong> {popup.type}</div>
      </>
    ) : (
      <div style={{ fontStyle: "italic" }}>{popup.type}</div>
    )}
  </div>
)}
    </div>
  );
}

export default MapChart;
